contracts/CLXToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

interface IERC20 {
    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);
    function totalSupply() external view returns (uint256);
    function balanceOf(address account) external view returns (uint256);
    function transfer(address to, uint256 amount) external returns (bool);
    function allowance(address owner, address spender) external view returns (uint256);
    function approve(address spender, uint256 amount) external returns (bool);
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
}

contract CLXToken is IERC20 {
    string  public constant name     = "CrossLedger Token";
    string  public constant symbol   = "CLX";
    uint8   public constant decimals = 18;
    uint256 public constant TOTAL_SUPPLY = 1_000_000_000 * 10**18;

    address public owner;
    address public escrowContract;
    bool    public tradingEnabled;

    mapping(address => uint256) private _balances;
    mapping(address => mapping(address => uint256)) private _allowances;

    enum WalletTier { None, Basic, Professional, Enterprise }
    mapping(address => WalletTier) public walletTier;

    uint256 public constant FEE_DISCOUNT_BASIC        = 500;
    uint256 public constant FEE_DISCOUNT_PROFESSIONAL = 1500;
    uint256 public constant FEE_DISCOUNT_ENTERPRISE   = 3000;

    mapping(address => uint256) public stakedBalance;
    mapping(address => uint256) public stakeTimestamp;
    uint256 public constant MIN_STAKE_PERIOD  = 30 days;
    uint256 public constant STAKE_REWARD_RATE = 500;

    event TierAssigned(address indexed user, WalletTier tier);
    event Staked(address indexed user, uint256 amount);
    event Unstaked(address indexed user, uint256 amount, uint256 reward);
    event EscrowContractSet(address indexed escrow);
    event TradingEnabled();

    modifier onlyOwner() { require(msg.sender == owner, "CLX: not owner"); _; }
    modifier onlyEscrow() { require(msg.sender == escrowContract, "CLX: not escrow"); _; }

    constructor(address _treasury) {
        owner = msg.sender;
        _balances[_treasury] = TOTAL_SUPPLY;
        emit Transfer(address(0), _treasury, TOTAL_SUPPLY);
    }

    function totalSupply() external pure override returns (uint256) { return TOTAL_SUPPLY; }
    function balanceOf(address account) external view override returns (uint256) { return _balances[account]; }

    function transfer(address to, uint256 amount) external override returns (bool) {
        _transfer(msg.sender, to, amount); return true;
    }

    function allowance(address _owner, address spender) external view override returns (uint256) {
        return _allowances[_owner][spender];
    }

    function approve(address spender, uint256 amount) external override returns (bool) {
        _allowances[msg.sender][spender] = amount;
        emit Approval(msg.sender, spender, amount); return true;
    }

    function transferFrom(address from, address to, uint256 amount) external override returns (bool) {
        require(_allowances[from][msg.sender] >= amount, "CLX: insufficient allowance");
        _allowances[from][msg.sender] -= amount;
        _transfer(from, to, amount); return true;
    }

    function _transfer(address from, address to, uint256 amount) internal {
        require(from != address(0) && to != address(0), "CLX: zero address");
        require(_balances[from] >= amount, "CLX: insufficient balance");
        _balances[from] -= amount;
        _balances[to]   += amount;
        emit Transfer(from, to, amount);
    }

    function assignTier(address user, WalletTier tier) external onlyOwner {
        walletTier[user] = tier; emit TierAssigned(user, tier);
    }

    function getFeeDiscount(address user) external view returns (uint256) {
        WalletTier tier = walletTier[user];
        if (tier == WalletTier.Enterprise)   return FEE_DISCOUNT_ENTERPRISE;
        if (tier == WalletTier.Professional) return FEE_DISCOUNT_PROFESSIONAL;
        if (tier == WalletTier.Basic)        return FEE_DISCOUNT_BASIC;
        return 0;
    }

    function stake(uint256 amount) external {
        require(amount > 0, "CLX: zero stake");
        require(_balances[msg.sender] >= amount, "CLX: insufficient balance");
        if (stakedBalance[msg.sender] > 0) _claimReward(msg.sender);
        _balances[msg.sender]  -= amount;
        stakedBalance[msg.sender] += amount;
        stakeTimestamp[msg.sender] = block.timestamp;
        emit Staked(msg.sender, amount);
    }

    function unstake() external {
        uint256 staked = stakedBalance[msg.sender];
        require(staked > 0, "CLX: nothing staked");
        require(block.timestamp >= stakeTimestamp[msg.sender] + MIN_STAKE_PERIOD, "CLX: too early");
        uint256 reward = _calculateReward(msg.sender);
        stakedBalance[msg.sender] = 0;
        _balances[msg.sender] += staked + reward;
        emit Unstaked(msg.sender, staked, reward);
    }

    function _calculateReward(address user) internal view returns (uint256) {
        uint256 duration = block.timestamp - stakeTimestamp[user];
        return (stakedBalance[user] * STAKE_REWARD_RATE * duration) / (365 days * 10000);
    }

    function _claimReward(address user) internal {
        uint256 reward = _calculateReward(user);
        if (reward > 0) { _balances[user] += reward; stakeTimestamp[user] = block.timestamp; }
    }

    function pendingReward(address user) external view returns (uint256) {
        if (stakedBalance[user] == 0) return 0;
        return _calculateReward(user);
    }

    function setEscrowContract(address _escrow) external onlyOwner {
        require(_escrow != address(0), "CLX: zero address");
        escrowContract = _escrow; emit EscrowContractSet(_escrow);
    }

    function enableTrading() external onlyOwner { tradingEnabled = true; emit TradingEnabled(); }

    function transferOwnership(address newOwner) external onlyOwner {
        require(newOwner != address(0), "CLX: zero address"); owner = newOwner;
    }
}

contracts/CrossLedgerEscrow.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

interface ICLXToken {
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
    function transfer(address to, uint256 amount) external returns (bool);
    function getFeeDiscount(address user) external view returns (uint256);
}

interface IDocumentRegistry {
    function isVerified(bytes32 docHash) external view returns (bool);
}

contract CrossLedgerEscrow {

    enum TradeStatus { Created, Funded, DocumentsLodged, InTransit, Delivered, Completed, Disputed, Cancelled, Refunded }

    struct TradeConditions {
        bytes32[] requiredDocHashes;
        uint256   deliveryDeadline;
        bool      requiresBuyerConfirm;
        string    originPort;
        string    destinationPort;
        string    commodityType;
        uint256   quantityMT;
    }

    struct Trade {
        bytes32        tradeId;
        address        buyer;
        address        seller;
        uint256        amount;
        uint256        platformFee;
        TradeStatus    status;
        TradeConditions conditions;
        uint256        createdAt;
        uint256        fundedAt;
        uint256        completedAt;
        bool           buyerConfirmed;
        bool           sellerConfirmed;
    }

    address public owner;
    address public feeCollector;
    ICLXToken public clxToken;
    IDocumentRegistry public docRegistry;

    uint256 public constant BASE_FEE_BPS = 30;
    uint256 public constant DISPUTE_PERIOD = 7 days;

    mapping(bytes32 => Trade) public trades;
    mapping(address => bytes32[]) public buyerTrades;
    mapping(address => bytes32[]) public sellerTrades;
    mapping(address => bool) public arbitrators;
    mapping(address => bool) public kycVerified;

    uint256 public totalTradeVolume;
    uint256 public totalFeesCollected;
    uint256 public tradeCount;

    event TradeCreated(bytes32 indexed tradeId, address indexed buyer, address indexed seller, uint256 amount, string commodityType);
    event TradeFunded(bytes32 indexed tradeId, uint256 amount, uint256 fee);
    event DocumentsLodged(bytes32 indexed tradeId, bytes32[] docHashes);
    event ShipmentConfirmed(bytes32 indexed tradeId, string trackingRef);
    event DeliveryConfirmed(bytes32 indexed tradeId, address confirmedBy);
    event PaymentReleased(bytes32 indexed tradeId, address seller, uint256 amount);
    event TradeDisputed(bytes32 indexed tradeId, address raisedBy, string reason);
    event DisputeResolved(bytes32 indexed tradeId, address winner);
    event TradeCancelled(bytes32 indexed tradeId);
    event RefundIssued(bytes32 indexed tradeId, address buyer, uint256 amount);
    event KYCVerified(address indexed user);

    modifier onlyOwner() { require(msg.sender == owner, "Escrow: not owner"); _; }
    modifier onlyArbitrator() { require(arbitrators[msg.sender], "Escrow: not arbitrator"); _; }
    modifier tradeExists(bytes32 tradeId) { require(trades[tradeId].createdAt > 0, "Escrow: not found"); _; }

    constructor(address _clxToken, address _docRegistry, address _feeCollector) {
        owner = msg.sender;
        clxToken = ICLXToken(_clxToken);
        docRegistry = IDocumentRegistry(_docRegistry);
        feeCollector = _feeCollector;
        arbitrators[msg.sender] = true;
    }

    function createTrade(address _buyer, uint256 _amount, TradeConditions calldata _conditions)
        external returns (bytes32 tradeId)
    {
        require(kycVerified[msg.sender] && kycVerified[_buyer], "Escrow: KYC required");
        require(_buyer != address(0) && _buyer != msg.sender, "Escrow: invalid buyer");
        require(_amount > 0, "Escrow: zero amount");
        require(_conditions.deliveryDeadline > block.timestamp + 1 days, "Escrow: deadline too soon");

        tradeId = keccak256(abi.encodePacked(msg.sender, _buyer, _amount, block.timestamp, tradeCount++));

        Trade storage t = trades[tradeId];
        t.tradeId    = tradeId;
        t.seller     = msg.sender;
        t.buyer      = _buyer;
        t.amount     = _amount;
        t.status     = TradeStatus.Created;
        t.conditions = _conditions;
        t.createdAt  = block.timestamp;

        uint256 discount = clxToken.getFeeDiscount(_buyer);
        uint256 effectiveFee = BASE_FEE_BPS > discount / 100 ? BASE_FEE_BPS - discount / 100 : 0;
        t.platformFee = (_amount * effectiveFee) / 10000;

        buyerTrades[_buyer].push(tradeId);
        sellerTrades[msg.sender].push(tradeId);

        emit TradeCreated(tradeId, _buyer, msg.sender, _amount, _conditions.commodityType);
    }

    function fundEscrow(bytes32 tradeId) external tradeExists(tradeId) {
        Trade storage t = trades[tradeId];
        require(msg.sender == t.buyer, "Escrow: not buyer");
        require(t.status == TradeStatus.Created, "Escrow: invalid status");
        require(kycVerified[msg.sender], "Escrow: KYC required");

        bool success = clxToken.transferFrom(msg.sender, address(this), t.amount + t.platformFee);
        require(success, "Escrow: transfer failed");

        t.status   = TradeStatus.Funded;
        t.fundedAt = block.timestamp;
        emit TradeFunded(tradeId, t.amount, t.platformFee);
    }

    function lodgeDocuments(bytes32 tradeId, bytes32[] calldata docHashes) external tradeExists(tradeId) {
        Trade storage t = trades[tradeId];
        require(msg.sender == t.seller, "Escrow: not seller");
        require(t.status == TradeStatus.Funded, "Escrow: not funded");

        for (uint i = 0; i < t.conditions.requiredDocHashes.length; i++) {
            require(docRegistry.isVerified(t.conditions.requiredDocHashes[i]), "Escrow: doc not verified");
        }

        t.status = TradeStatus.DocumentsLodged;
        emit DocumentsLodged(tradeId, docHashes);
    }

    function confirmShipment(bytes32 tradeId, string calldata trackingRef) external tradeExists(tradeId) {
        Trade storage t = trades[tradeId];
        require(msg.sender == t.seller, "Escrow: not seller");
        require(t.status == TradeStatus.DocumentsLodged, "Escrow: docs not lodged");
        t.status = TradeStatus.InTransit;
        emit ShipmentConfirmed(tradeId, trackingRef);
    }

    function confirmDelivery(bytes32 tradeId) external tradeExists(tradeId) {
        Trade storage t = trades[tradeId];
        require(msg.sender == t.buyer, "Escrow: not buyer");
        require(t.status == TradeStatus.InTransit || t.status == TradeStatus.DocumentsLodged, "Escrow: cannot confirm");
        t.buyerConfirmed = true;
        emit DeliveryConfirmed(tradeId, msg.sender);
        _releaseFunds(tradeId);
    }

    function autoRelease(bytes32 tradeId) external tradeExists(tradeId) {
        Trade storage t = trades[tradeId];
        require(t.status == TradeStatus.InTransit || t.status == TradeStatus.DocumentsLodged, "Escrow: cannot release");
        require(block.timestamp > t.conditions.deliveryDeadline + 14 days, "Escrow: too early");
        _releaseFunds(tradeId);
    }

    function _releaseFunds(bytes32 tradeId) internal {
        Trade storage t = trades[tradeId];
        t.status      = TradeStatus.Completed;
        t.completedAt = block.timestamp;
        totalTradeVolume   += t.amount;
        totalFeesCollected += t.platformFee;
        if (t.platformFee > 0) clxToken.transfer(feeCollector, t.platformFee);
        clxToken.transfer(t.seller, t.amount);
        emit PaymentReleased(tradeId, t.seller, t.amount);
    }

    function raiseDispute(bytes32 tradeId, string calldata reason) external tradeExists(tradeId) {
        Trade storage t = trades[tradeId];
        require(msg.sender == t.buyer || msg.sender == t.seller, "Escrow: not party");
        require(t.status == TradeStatus.Funded || t.status == TradeStatus.DocumentsLodged || t.status == TradeStatus.InTransit, "Escrow: cannot dispute");
        t.status = TradeStatus.Disputed;
        emit TradeDisputed(tradeId, msg.sender, reason);
    }

    function resolveDispute(bytes32 tradeId, bool releaseToSeller) external onlyArbitrator tradeExists(tradeId) {
        Trade storage t = trades[tradeId];
        require(t.status == TradeStatus.Disputed, "Escrow: not disputed");
        if (releaseToSeller) {
            _releaseFunds(tradeId);
            emit DisputeResolved(tradeId, t.seller);
        } else {
            t.status = TradeStatus.Refunded;
            clxToken.transfer(t.buyer, t.amount + t.platformFee);
            emit RefundIssued(tradeId, t.buyer, t.amount + t.platformFee);
            emit DisputeResolved(tradeId, t.buyer);
        }
    }

    function cancelTrade(bytes32 tradeId) external tradeExists(tradeId) {
        Trade storage t = trades[tradeId];
        require(msg.sender == t.buyer || msg.sender == t.seller, "Escrow: not party");
        if (t.status == TradeStatus.Created) {
            t.status = TradeStatus.Cancelled;
            emit TradeCancelled(tradeId);
            return;
        }
        if (t.status == TradeStatus.Funded && msg.sender == t.buyer) {
            t.status = TradeStatus.Refunded;
            clxToken.transfer(t.buyer, t.amount + t.platformFee);
            emit RefundIssued(tradeId, t.buyer, t.amount + t.platformFee);
            return;
        }
        revert("Escrow: cannot cancel");
    }

    function verifyKYC(address user) external onlyOwner { kycVerified[user] = true; emit KYCVerified(user); }
    function addArbitrator(address arb) external onlyOwner { arbitrators[arb] = true; }
    function setFeeCollector(address _fc) external onlyOwner { feeCollector = _fc; }
    function getTradeStatus(bytes32 tradeId) external view returns (TradeStatus) { return trades[tradeId].status; }
    function getBuyerTrades(address buyer) external view returns (bytes32[] memory) { return buyerTrades[buyer]; }
    function getSellerTrades(address seller) external view returns (bytes32[] memory) { return sellerTrades[seller]; }
}

contracts/DocumentRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract DocumentRegistry {

    enum DocType {
        BillOfLading,
        CertificateOfOrigin,
        CommercialInvoice,
        PhytosanitaryCertificate,
        PackingList,
        CustomsDeclaration,
        InsuranceCertificate,
        InspectionReport,
        PurchaseAgreement,
        Other
    }

    enum VerificationStatus { Pending, Verified, Rejected, Revoked }

    struct Document {
        bytes32            docHash;
        DocType            docType;
        VerificationStatus status;
        address            submitter;
        address            verifier;
        uint256            submittedAt;
        uint256            verifiedAt;
        bytes32            tradeId;
        string             ipfsCid;
        string             description;
        bool               isPublic;
    }

    address public owner;
    mapping(bytes32 => Document) public documents;
    mapping(address => bytes32[]) public submitterDocs;
    mapping(bytes32 => bytes32[]) public tradeDocs;
    mapping(address => bool) public verifiers;

    uint256 public totalDocsSubmitted;
    uint256 public totalDocsVerified;

    event DocumentSubmitted(bytes32 indexed docHash, address indexed submitter, DocType docType, bytes32 tradeId, string ipfsCid);
    event DocumentVerified(bytes32 indexed docHash, address indexed verifier, DocType docType);
    event DocumentRejected(bytes32 indexed docHash, address indexed verifier, string reason);
    event DocumentRevoked(bytes32 indexed docHash, string reason);
    event VerifierAdded(address indexed verifier);
    event VerifierRemoved(address indexed verifier);

    modifier onlyOwner() { require(msg.sender == owner, "Registry: not owner"); _; }
    modifier onlyVerifier() { require(verifiers[msg.sender], "Registry: not a verifier"); _; }
    modifier docExists(bytes32 docHash) { require(documents[docHash].submittedAt > 0, "Registry: not found"); _; }

    constructor() {
        owner = msg.sender;
        verifiers[msg.sender] = true;
    }

    function submitDocument(
        bytes32 docHash,
        DocType docType,
        bytes32 tradeId,
        string calldata ipfsCid,
        string calldata description,
        bool isPublic
    ) external returns (bytes32) {
        require(docHash != bytes32(0), "Registry: empty hash");
        require(documents[docHash].submittedAt == 0, "Registry: already submitted");
        require(bytes(ipfsCid).length > 0, "Registry: no IPFS CID");

        documents[docHash] = Document({
            docHash:     docHash,
            docType:     docType,
            status:      VerificationStatus.Pending,
            submitter:   msg.sender,
            verifier:    address(0),
            submittedAt: block.timestamp,
            verifiedAt:  0,
            tradeId:     tradeId,
            ipfsCid:     ipfsCid,
            description: description,
            isPublic:    isPublic
        });

        submitterDocs[msg.sender].push(docHash);
        if (tradeId != bytes32(0)) tradeDocs[tradeId].push(docHash);
        totalDocsSubmitted++;

        emit DocumentSubmitted(docHash, msg.sender, docType, tradeId, ipfsCid);
        return docHash;
    }

    function submitDocumentBatch(
        bytes32[]     calldata docHashes,
        DocType[]     calldata docTypes,
        bytes32                tradeId,
        string[]      calldata ipfsCids,
        string[]      calldata descriptions
    ) external {
        require(docHashes.length == docTypes.length && docHashes.length == ipfsCids.length, "Registry: length mismatch");
        for (uint i = 0; i < docHashes.length; i++) {
            require(documents[docHashes[i]].submittedAt == 0, "Registry: duplicate");
            documents[docHashes[i]] = Document({
                docHash:     docHashes[i],
                docType:     docTypes[i],
                status:      VerificationStatus.Pending,
                submitter:   msg.sender,
                verifier:    address(0),
                submittedAt: block.timestamp,
                verifiedAt:  0,
                tradeId:     tradeId,
                ipfsCid:     ipfsCids[i],
                description: descriptions[i],
                isPublic:    true
            });
            submitterDocs[msg.sender].push(docHashes[i]);
            if (tradeId != bytes32(0)) tradeDocs[tradeId].push(docHashes[i]);
        }
        totalDocsSubmitted += docHashes.length;
    }

    function verifyDocument(bytes32 docHash) external onlyVerifier docExists(docHash) {
        Document storage doc = documents[docHash];
        require(doc.status == VerificationStatus.Pending, "Registry: not pending");
        doc.status     = VerificationStatus.Verified;
        doc.verifier   = msg.sender;
        doc.verifiedAt = block.timestamp;
        totalDocsVerified++;
        emit DocumentVerified(docHash, msg.sender, doc.docType);
    }

    function verifyDocumentBatch(bytes32[] calldata docHashes) external onlyVerifier {
        for (uint i = 0; i < docHashes.length; i++) {
            Document storage doc = documents[docHashes[i]];
            if (doc.submittedAt > 0 && doc.status == VerificationStatus.Pending) {
                doc.status     = VerificationStatus.Verified;
                doc.verifier   = msg.sender;
                doc.verifiedAt = block.timestamp;
                totalDocsVerified++;
                emit DocumentVerified(docHashes[i], msg.sender, doc.docType);
            }
        }
    }

    function rejectDocument(bytes32 docHash, string calldata reason) external onlyVerifier docExists(docHash) {
        require(documents[docHash].status == VerificationStatus.Pending, "Registry: not pending");
        documents[docHash].status = VerificationStatus.Rejected;
        emit DocumentRejected(docHash, msg.sender, reason);
    }

    function revokeDocument(bytes32 docHash, string calldata reason) external onlyVerifier docExists(docHash) {
        documents[docHash].status = VerificationStatus.Revoked;
        emit DocumentRevoked(docHash, reason);
    }

    function isVerified(bytes32 docHash) external view returns (bool) {
        return documents[docHash].status == VerificationStatus.Verified;
    }

    function getVerificationProof(bytes32 docHash) external view returns (
        bool verified, address verifier, uint256 verifiedAt, DocType docType, string memory ipfsCid, string memory description
    ) {
        Document storage doc = documents[docHash];
        return (doc.status == VerificationStatus.Verified, doc.verifier, doc.verifiedAt, doc.docType, doc.ipfsCid, doc.description);
    }

    function getTradeDocuments(bytes32 tradeId) external view returns (bytes32[] memory) {
        return tradeDocs[tradeId];
    }

    function allTradeDocsVerified(bytes32 tradeId) external view returns (bool) {
        bytes32[] storage docs = tradeDocs[tradeId];
        if (docs.length == 0) return false;
        for (uint i = 0; i < docs.length; i++) {
            if (documents[docs[i]].status != VerificationStatus.Verified) return false;
        }
        return true;
    }

    function getSubmitterDocuments(address submitter) external view returns (bytes32[] memory) {
        return submitterDocs[submitter];
    }

    function addVerifier(address v) external onlyOwner { verifiers[v] = true; emit VerifierAdded(v); }
    function removeVerifier(address v) external onlyOwner { verifiers[v] = false; emit VerifierRemoved(v); }
    function transferOwnership(address newOwner) external onlyOwner { require(newOwner != address(0)); owner = newOwner; }
}

